import numpy as np

def find_s(measurements, n):
    for candidate in range(1, 2**n):
        s = np.array([int(b) for b in format(candidate, f'0{n}b')])
        valid = True
        for y in measurements:
            if np.dot(y, s) % 2 != 0:
                valid = False
                break
        if valid:
            return ''.join(map(str, s))
    return '0' * n

measurements = [[1,1,0], [0,1,1]]
print(f"Found s = {find_s(measurements, 3)}")
